document.addEventListener("DOMContentLoaded", () => {
  const e = document.querySelector(".loader");
  e &&
    window.addEventListener("load", () => {
      setTimeout(() => e.classList.add("hidden"), 600);
    });
  const t = document.querySelector("nav"),
    n = () => {
      window.scrollY > 60
        ? t?.classList.add("scrolled")
        : t?.classList.remove("scrolled");
    };
  (window.addEventListener("scroll", n, { passive: !0 }), n());
  const o = window.location.pathname.split("/").pop() || "index.html";
  document.querySelectorAll(".nav-links a").forEach((e) => {
    e.getAttribute("href").split("/").pop() === o && e.classList.add("active");
  });
  const s = document.getElementById("navToggle"),
    l = document.getElementById("navLinks");
  s?.addEventListener("click", () => {
    (s.classList.toggle("open"), l.classList.toggle("open"));
  });
  const r = document.querySelectorAll(
      ".reveal, .reveal-left, .reveal-right, .stagger",
    ),
    a = new IntersectionObserver(
      (e) => {
        e.forEach((e) => {
          e.isIntersecting &&
            (e.target.classList.add("visible"), a.unobserve(e.target));
        });
      },
      { threshold: 0.12, rootMargin: "0px 0px -60px 0px" },
    );
  r.forEach((e) => a.observe(e));
  const c = document.querySelectorAll(".hero-slide");
  if (c.length > 1) {
    const e = [...c],
      t = e[0].parentNode;
    (e.sort(() => Math.random() - 0.5),
      e.forEach((e) => t.appendChild(e)),
      document
        .querySelectorAll(".hero-slide")
        .forEach((e) => e.classList.remove("active")),
      document.querySelector(".hero-slide").classList.add("active"));
    let n = 0;
    const o = document.querySelectorAll(".hero-slide");
    setInterval(() => {
      (o[n].classList.remove("active"),
        (n = (n + 1) % o.length),
        o[n].classList.add("active"));
    }, 3e3);
  }
  const i = document.querySelectorAll(".filter-btn"),
    d = document.querySelectorAll(".masonry-item");
  i.forEach((e) => {
    e.addEventListener("click", () => {
      (i.forEach((e) => e.classList.remove("active")),
        e.classList.add("active"));
      const t = e.dataset.filter;
      if (
        (document.querySelector(".gallery-empty")?.remove(),
        d.forEach((e) => {
          const n = "all" === t || e.dataset.category === t;
          e.style.display = n ? "block" : "none";
        }),
        "all" !== t)
      ) {
        if (![...d].some((e) => e.dataset.category === t)) {
          const e = document.createElement("p");
          ((e.className = "gallery-empty"),
            (e.textContent = "Nothing yet — be the first!"),
            document.querySelector(".gallery-masonry").appendChild(e));
        }
      }
    });
  });
  const m = new URLSearchParams(window.location.search).get("filter");
  if (m) {
    const e = document.querySelector(`.filter-btn[data-filter="${m}"]`);
    e && e.click();
  }
  const u = document.querySelector(".lightbox"),
    y = document.querySelector(".lightbox-img"),
    v = document.querySelector(".lightbox-close");
  if (u && y) {
    document.querySelectorAll(".masonry-item img").forEach((e) => {
      e.addEventListener("click", () => {
        ((y.src = e.src),
          u.classList.add("open"),
          (document.body.style.overflow = "hidden"));
      });
    });
    const e = () => {
      (u.classList.remove("open"), (document.body.style.overflow = ""));
    };
    (v?.addEventListener("click", e),
      u.addEventListener("click", (t) => {
        t.target === u && e();
      }),
      document.addEventListener("keydown", (t) => {
        "Escape" === t.key && e();
      }));
  }
  const p = document.querySelector(".page-transition");
  p &&
    (p.classList.add("exiting"),
    setTimeout(() => p.classList.remove("exiting"), 700),
    window.addEventListener("pageshow", (e) => {
      e.persisted &&
        (p.classList.remove("entering"), p.classList.remove("exiting"));
    }),
    document.querySelectorAll("a[href]").forEach((e) => {
      const t = e.getAttribute("href");
      t &&
        !t.startsWith("http") &&
        !t.startsWith("#") &&
        !t.startsWith("mailto") &&
        e.addEventListener("click", (e) => {
          (e.preventDefault(),
            p.classList.add("entering"),
            setTimeout(() => {
              window.location.href = t;
            }, 600));
        });
    }));
  const f = document.querySelector(".contact-form");
  function h(e, t) {
    let n = e.querySelector(".form-error");
    (n ||
      ((n = document.createElement("p")),
      (n.className = "form-error"),
      (n.style.cssText =
        "color:#c0392b;font-family:var(--font-body);text-align:center;margin-top:1rem;"),
      e.appendChild(n)),
      (n.textContent = t));
  }
  f &&
    f.addEventListener("submit", async (e) => {
      e.preventDefault();
      const t = f.querySelector('button[type="submit"]'),
        n = t ? t.textContent : "";
      t && ((t.disabled = !0), (t.textContent = "Sending..."));
      try {
        const e = new FormData(f),
          t = await fetch("https://api.web3forms.com/submit", {
            method: "POST",
            body: e,
          });
        t.ok
          ? (f.innerHTML =
              '<p style="font-family:var(--font-display);font-size:1.5rem;font-style:italic;color:var(--taupe);text-align:center;padding:3rem 0;">Thank you! I\'ll be in touch within 48 hours.</p>')
          : 429 === t.status
            ? h(f, "Too many requests — please wait a minute and try again.")
            : h(f, "Something went wrong. Please try again or email directly.");
      } catch {
        h(f, "Network error — please check your connection and try again.");
      } finally {
        t && f.contains(t) && ((t.disabled = !1), (t.textContent = n));
      }
    });
  const g = document.getElementById("service");
  if (g) {
    (g
      .closest(".form-group")
      .insertAdjacentHTML(
        "afterend",
        '\n        <div class="form-row" id="event-fields" style="display:none">\n        <div class="form-group">\n        <label class="form-label" for="event-date">Date</label>\n        <input class="form-input" type="date" id="event-date" name="event_date" />\n        </div>\n        <div class="form-group">\n        <label class="form-label" for="event-location">Location</label>\n        <input class="form-input" type="text" id="event-location" name="event_location" placeholder="Venue or city" />\n        </div>\n        </div>\n        ',
      ),
      g.addEventListener("change", () => {
        const e = ["wedding", "event"].includes(g.value);
        document.getElementById("event-fields").style.display = e
          ? "flex"
          : "none";
      }));
  }
  const L = document.getElementById("heartCursor");
  L &&
    window.innerWidth > 600 &&
    ((document.body.style.cursor = "none"),
    document.addEventListener("mousemove", (e) => {
      ((L.style.left = e.clientX + "px"), (L.style.top = e.clientY + "px"));
    }),
    document.addEventListener("click", (e) => {
      const t = document.createElement("div");
      ((t.className = "click-heart"),
        (t.textContent = "♥"),
        (t.style.left = e.clientX + "px"),
        (t.style.top = e.clientY + "px"),
        document.body.appendChild(t),
        setTimeout(() => t.remove(), 800));
    }));
});
